var n = 260 + R.int(140);
var flakes = [];
for (var i = 0; i < n; i++) {
  flakes.push({
    x: (R.dec() - 0.5) * 2.0,
    y: R.dec(),
    z: 0.1 + R.dec() * 0.9,
    tw: R.dec() * Math.PI * 2
  });
}
var trees = [];
for (var t = 0; t < 64; t++) {
  trees.push({
    side: R.dec() < 0.5 ? -1 : 1,
    lane: R.dec(),
    y: R.dec(),
    h: 0.12 + R.dec() * 0.22
  });
}
return Object.assign({}, state, { flakes: flakes, trees: trees, runT: 0 });
